* basis, WITHOUT WARRANTY OF ANY KIND, either express or implied. See the
* License for the specific  language  governing  rights  and  limitations
* under the License.
* The Original Code is Openbravo ERP.
* The Initial Developer of the Original Code is Openbravo SLU
* All portions are Copyright (C) 2001-2016 Openbravo SLU
* All Rights Reserved.
* Contributor(s):  ______________________________________.
************************************************************************/
  v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Result NUMBER:=1; -- 0=failure
  v_p_Record_ID VARCHAR2(32);
  v_AD_User_ID VARCHAR2(32);
  v_AD_Client_ID VARCHAR2(32);
  v_PeriodStatus VARCHAR2(60);

  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;

    --
    v_ad_org_id VARCHAR2(32);  
    v_fin_financial_account_id VARCHAR2(32);  
    v_c_bpartner_id VARCHAR2(32);  
    v_paymentmethod_id VARCHAR2(32);  
    v_c_glitem_id VARCHAR2(32);  
    v_c_currency_id VARCHAR2(32);  
    v_finacc_transaction_id VARCHAR2(32);  
    v_reconciliation_id VARCHAR2(32);  
    v_payment_id VARCHAR2(32);  
    v_dateactual DATE;
    v_accounting_date DATE;

    v_deposit_amount NUMBER:=0;
    v_refund_amount NUMBER:=0;
    v_line NUMBER:=0;

    v_Status VARCHAR(60) ;
    v_type_of_operation VARCHAR(60) ;
    v_projectcategory   VARCHAR(60);
    v_temppricelist     VARCHAR(60);
    v_processed VARCHAR(60);
    v_posted VARCHAR(60);
    v_isreconciled VARCHAR(60);
    v_description VARCHAR(300);
    FINISH_PROCESS BOOLEAN:=false;
  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
  BEGIN --BODY
    -- Get PARAMETERS
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        i.AD_User_ID,
        i.AD_Client_ID,
        i.AD_Org_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date,
        p.P_Date_To
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
        ON i.AD_PInstance_ID=p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      ORDER BY p.SeqNo
      )
    LOOP
      v_p_Record_ID:=Cur_Parameter.Record_ID;
      v_AD_User_ID:=Cur_Parameter.AD_User_ID;
      v_AD_Client_ID:=Cur_Parameter.AD_Client_ID;
    END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_p_Record_ID) ;
    -- Check that we have some restrictions

	-- RECORD VALUES
	Select 	  cie.dateactual 		, cie.accounting_date		, cie.deposit_amount		, cie.refund_amount
		, cie.ad_org_id			, cie.type_of_operation		, cie.fin_financial_account_id  , cie.c_bpartner_id
		, cie.fin_paymentmethod_id  	, cie.c_glitem_id		, cie.description		, o.c_currency_id
		, cie.processed			, fin_finacc_transaction_id	, cie.isreconciled
	INTO 	  v_dateactual			, v_accounting_date		, v_deposit_amount		, v_refund_amount
		, v_ad_org_id			, v_type_of_operation		, v_fin_financial_account_id	, v_c_bpartner_id
		, v_paymentmethod_id		, v_c_glitem_id			, v_description			, v_c_currency_id
		, v_processed			, v_finacc_transaction_id	, v_isreconciled
	From ssccso_cash_inc_exp cie
		join ad_org o on cie.ad_org_id = o.ad_org_id    
	Where cie.ssccso_cash_inc_exp_id = v_p_Record_ID;

	If(v_processed='N')Then --PROCESAR
		--SE COMPRUEBA SI EL PERÍODO ESTÁ CERRADO
		SELECT openclose INTO v_PeriodStatus FROM c_period WHERE v_accounting_date>=startdate AND v_accounting_date <= enddate ;

		IF (v_PeriodStatus='O')THEN
			RAISE_APPLICATION_ERROR(-20000, '@PeriodNotAvailable@');
		END IF;


		if(v_deposit_amount>v_refund_amount) 
			Then 	v_Status	:='RDNC';
			Else 	v_Status	:='PWNC';
		End If;

		v_line		:= ((select max(line) from fin_finacc_transaction where fin_financial_account_id = v_fin_financial_account_id) + 10);
		v_finacc_transaction_id := get_uuid();
		INSERT INTO fin_finacc_transaction(
			  fin_finacc_transaction_id		, ad_client_id			, ad_org_id		, createdby		, updatedby
			, dateacct				, statementdate			, trxtype		, depositamt		, fin_financial_account_id
			, c_currency_id				, line				, status 		, c_glitem_id		, c_bpartner_id
			, description				, processed			, paymentamt		, em_aprm_processed )
		VALUES (  v_finacc_transaction_id		, v_AD_Client_ID		, v_ad_org_id		, v_AD_User_ID		, v_AD_User_ID
			, v_accounting_date			, v_dateactual			, v_type_of_operation	, v_deposit_amount	, v_fin_financial_account_id
			, v_c_currency_id			, v_line			, v_Status		, v_c_glitem_id		, v_c_bpartner_id
			, v_description				, 'Y'				, v_refund_amount	, 'R');
		update fin_financial_account set
			  currentbalance =  currentbalance + (v_deposit_amount - v_refund_amount)
		Where  fin_financial_account_id = v_fin_financial_account_id;

		update ssccso_cash_inc_exp set 
			  status = 'PR'
			, processed = 'Y'
			, fin_finacc_transaction_id = v_finacc_transaction_id 
		Where ssccso_cash_inc_exp_id = v_p_Record_ID;

	ELSE-- Reactivar
		If(v_isreconciled = 'Y')Then
			RAISE_APPLICATION_ERROR(-20000, '@DocBeingProcessed@');
		End IF;
		Select fft.posted	, fin_reconciliation_id	, status	, fin_payment_id	, depositamt		, paymentamt
			Into v_posted	, v_reconciliation_id	, v_Status	, v_payment_id		, v_deposit_amount	, v_refund_amount
		From fin_finacc_transaction fft
		Where fft.fin_finacc_transaction_id  = v_finacc_transaction_id;
		If(v_posted='Y')Then
			RAISE_APPLICATION_ERROR(-20000, '@PostedDocument@');
		End If;
		If(v_reconciliation_id is not null or v_Status = 'RPPC')Then
			RAISE_APPLICATION_ERROR(-20000, '@APRM_ReconciledDocument@');
		End If;
		update ssccso_cash_inc_exp set 
			  status = 'DR'
			, processed = 'N'
			, fin_finacc_transaction_id = null 
		Where ssccso_cash_inc_exp_id = v_p_Record_ID; 

		If(v_deposit_amount>v_refund_amount) 
			Then 	v_Status	:='RPR';
			Else 	v_Status	:='PPM';
		End If;

		update fin_finacc_transaction set 
			  status = v_Status
			, processed = 'N'
			, em_aprm_processed = 'P'
		Where fin_finacc_transaction_id = v_finacc_transaction_id;

		DELETE FROM fin_finacc_transaction where fin_finacc_transaction_id = v_finacc_transaction_id;

		UPDATE fin_financial_account set
			  currentbalance =  currentbalance - (v_deposit_amount + v_refund_amount)
		WHERE fin_financial_account_id = v_fin_financial_account_id;
	End IF;


	v_Message := '@Success@';

    --<<FINISH_PROCESS>>
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', v_Result, v_Message) ;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
  ROLLBACK;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SSCCSO_PROCESS
